checker_dsl:
EXISTS (`taint source node SRC`, `taint sink node SINK`) {
  AND {
    (`SRC is an instance of ActiveThreatModelSource (representing user-provided input)`),
    (`SINK is an instance of RegexInjectionSink (representing regular expression pattern construction/compilation)`),
    EXISTS (`taint flow path PATH`) {
      AND {
        (`PATH starts at source node SRC`),
        (`PATH ends at sink node SINK`),
        FORALL (`node N on PATH`) {
          NOT { (`N is an instance of RegexInjectionSanitizer (a sanitizing operation that stops taint flow)`) }
        }
      }
    }
  }
}
